      result._.length === 0 ? (result[expectedKey] = arg) : result._.push(arg)
      expectingValue = false
      continue
    }

    if (arg === '--') continue

    if (arg.startsWith('--')) {
      const equalsIndex = arg.indexOf('=')
      if (equalsIndex > 0) {
        const key = arg.slice(2, equalsIndex)
        result[key] = arg.slice(equalsIndex + 1)
      } else if (arg === '--' + arg.slice(2)) {
        result[arg.slice(2)] = true
      } else {
        expectingValue = true
        expectedKey = arg.slice(2)
      }
    } else {
      result._.push(arg)
    }
  }

  return result
}

